def bei_value(Le: float, bi: float) -> float:
    """Calculate the effective width of the concrete flange at one side of the web.

    EN 1994-1-1 (2004). Clause 5.4.1.2 (5)

    Args:
        Le (float): The equivalent span length in mm.
        bi (float): The geometric width from the outermost connector to the
            point halfway between adjacent webs or the free edge in mm.

    Returns:
        float: The effective width bei in mm.
    """
    return min(Le / 8.0, bi)


def beff_midspan_internal_support(b0: float, be1: float, be2: float) -> float:
    """Calculate the total effective width at mid-span or an internal support.

    EN 1994-1-1 (2004). Eq. (5.3)

    Args:
        b0 (float): The distance between the centers of the outermost
            connectors in mm.
        be1 (float): The effective width bei at the left side of the web in mm.
        be2 (float): The effective width bei at the right side of the web in mm.
            for each side of the web (calculated using Clause 5.4.1.2 (5)).

    Returns:
        float: The total effective width beff in mm.
    """
    return b0 + be1 + be2


def beta_i_factor(Le: float, bei: float) -> float:
    """Calculate the reduction factor for the effective width at an end support.

    EN 1994-1-1 (2004). Eq. (5.5)

    Args:
        Le (float): The equivalent span length of the end span in mm.
        bei (float): The effective width bei at mid-span of the end
            span in mm.

    Returns:
        float: The reduction factor beta_i (dimensionless, <= 1.0).
    """
    if bei == 0:
        return 1.0
    else:
        beta = 0.55 + 0.025 * (Le / bei)
    return min(beta, 1.0)


def beff_end_support(
    b0: float, beta1: float, beta2: float, be1: float, be2: float
) -> float:
    """Calculate the total effective width at an end support.

    EN 1994-1-1 (2004). Eq. (5.4)

    Args:
        b0 (float): The distance between the centers of the outermost
            connectors in mm.
        beta1 (float): The reduction factor beta_i for the left side of the web
            (calculated using Eq. (5.5)).
        beta2 (float): The reduction factor beta_i for the right side of the web
            (calculated using Eq. (5.5)).
        be1 (float): The effective width bei at the left side of the web in mm.
        be2 (float): The effective width bei at the right side of the web in mm.

    Returns:
        float: The total effective width beff in mm.
    """

    return b0 + beta1 * be1 + beta2 * be2


def get_effective_length_le_EN_1994_1_1(
    L: float, case: str = "end_span_sagging", L_adjacent: float = None
) -> float:
    """Calculate the effective length Le for shear lag assessment.

    Args:
        L (float): Length of the span under consideration.
        case (str): The specific region/case for Le calculation.
            Options:
            'end_span_sagging': Sagging moment area in an end span.
            'internal_span_sagging': Sagging moment area in an internal span.
            'internal_support': Hogging moment area at an internal support.
            'cantilever': Support and end area of a cantilever.
            Defaults to 'end_span_sagging'.
        L_adjacent (float, optional): Length of the adjacent span.
            Required only for 'internal_support' case.

    Returns:
        float: Effective length Le.

    Reference:
        EN 1994-1-1:2004, Figure 5.1.
    """
    if case == "end_span_sagging":
        # Le = 0.85 * L1
        return 0.85 * L

    if case == "internal_span_sagging":
        # Le = 0.70 * L2
        return 0.70 * L

    if case == "internal_support":
        if L_adjacent is None:
            raise ValueError("L_adjacent is required for internal_support case.")
        # Le = 0.25 * (L1 + L2)
        return 0.25 * (L + L_adjacent)

    if case == "cantilever":
        # Le = 2 * L3
        return 2.0 * L

    # Default fallback: Le is the distance between points of zero moment
    return L
